package dev.harrison.rendacomcarro.finance.domain;
import jakarta.persistence.*;import java.math.*;import java.time.LocalDate;import java.util.UUID;
@Entity @Table(name="obligation_installment") public class ObligationInstallment {@Id private UUID id;@ManyToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="obligation_id")private FinancialObligation obligation;@Column(name="sequence_number",nullable=false)private int sequenceNumber;@Column(name="due_date",nullable=false)private LocalDate dueDate;@Column(name="principal_amount",nullable=false,precision=14,scale=2)private BigDecimal principalAmount;@Column(name="interest_amount",nullable=false,precision=14,scale=2)private BigDecimal interestAmount;@Column(name="expected_amount",nullable=false,precision=14,scale=2)private BigDecimal expectedAmount;@Column(name="paid_amount",nullable=false,precision=14,scale=2)private BigDecimal paidAmount;@Enumerated(EnumType.STRING)@Column(nullable=false)private InstallmentStatus status;protected ObligationInstallment(){}public static ObligationInstallment create(FinancialObligation o,int s,LocalDate d,BigDecimal p,BigDecimal i,BigDecimal total){ObligationInstallment x=new ObligationInstallment();x.id=UUID.randomUUID();x.obligation=o;x.sequenceNumber=s;x.dueDate=d;x.principalAmount=p;x.interestAmount=i;x.expectedAmount=total;x.paidAmount=BigDecimal.ZERO.setScale(2);x.status=InstallmentStatus.PENDING;return x;}public UUID getId(){return id;}public int getSequenceNumber(){return sequenceNumber;}public LocalDate getDueDate(){return dueDate;}public BigDecimal getPrincipalAmount(){return principalAmount;}public BigDecimal getInterestAmount(){return interestAmount;}public BigDecimal getExpectedAmount(){return expectedAmount;}public BigDecimal getPaidAmount(){return paidAmount;}public InstallmentStatus getStatus(){return status;}}
